package main

import (
	"context"
	"encoding/json"
	"errors"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body.
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// in-memory placeholder for persisted configuration
var configuredWebhookURL string

// ConfigureWebhook handles POST requests to configure a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid JSON format",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	parsedURL, err := validateWebhookURL(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	if err := testWebhookURL(parsedURL.String()); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "failed to validate webhook URL",
		})
	}

	// Save the configuration.
	// Replace with persistent storage in real applications.
	configuredWebhookURL = parsedURL.String()

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "webhook configured successfully",
		"webhook_url": configuredWebhookURL,
	})
}

func validateWebhookURL(raw string) (*url.URL, error) {
	parsedURL, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("invalid webhook URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("webhook URL must use http or https scheme")
	}

	if parsedURL.Host == "" {
		return nil, errors.New("webhook URL must include a host")
	}

	if parsedURL.User != nil {
		return nil, errors.New("webhook URL must not contain user info")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, errors.New("webhook URL must include a valid host")
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, errors.New("webhook host could not be resolved")
	}

	for _, ip := range ips {
		if isPrivateOrRestrictedIP(ip) {
			return nil, errors.New("webhook URL host resolves to a restricted address")
		}
	}

	return parsedURL, nil
}

func testWebhookURL(target string) error {
	dialer := &net.Dialer{
		Timeout: 2 * time.Second,
	}

	transport := &http.Transport{
		Proxy: nil,
		DialContext: func(ctx context.Context, network, address string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(address)
			if err != nil {
				return nil, err
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
				if isPrivateOrRestrictedIP(ip) {
					return nil, errors.New("connection to restricted address is not allowed")
				}
			}

			return dialer.DialContext(ctx, network, net.JoinHostPort(host, port))
		},
		TLSHandshakeTimeout:   2 * time.Second,
		ResponseHeaderTimeout: 3 * time.Second,
		DisableKeepAlives:    true,
	}

	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}

			host := req.URL.Hostname()
			if host == "" {
				return errors.New("invalid redirect host")
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return err
			}
			for _, ip := range ips {
				if isPrivateOrRestrictedIP(ip) {
					return errors.New("redirected to restricted address")
				}
			}

			return nil
		},
	}

	httpReq, err := http.NewRequest(http.MethodGet, target, nil)
	if err != nil {
		return err
	}
	httpReq.Header.Set("Accept", "application/json")

	resp, err := client.Do(httpReq)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return errors.New("non-success status code")
	}

	return nil
}

func isPrivateOrRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	privateCIDRs := []string{
		"127.0.0.0/8",     // loopback
		"10.0.0.0/8",      // private
		"172.16.0.0/12",   // private
		"192.168.0.0/16",  // private
		"169.254.0.0/16",  // link-local
		"0.0.0.0/8",       // invalid
		"100.64.0.0/10",   // carrier-grade NAT
		"192.0.0.0/24",    // IETF protocol assignments
		"192.0.2.0/24",    // TEST-NET-1
		"198.18.0.0/15",   // benchmark testing
		"198.51.100.0/24", // TEST-NET-2
		"203.0.113.0/24",  // TEST-NET-3
		"224.0.0.0/4",     // multicast
		"240.0.0.0/4",     // reserved
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // unique local
		"fe80::/10",       // link-local
		"ff00::/8",        // multicast
	}

	for _, cidr := range privateCIDRs {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	_ = json.Valid // keep encoding/json imported as requested by task context

	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

