		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": parsedURL.String(),
	})
}

func validateWebhookURL(raw string) (*url.URL, error) {
	parsedURL, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("invalid webhook URL format")
	}

	if !parsedURL.IsAbs() {
		return nil, errors.New("webhook URL must be absolute")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("webhook URL must use http or https scheme")
	}

	if parsedURL.User != nil {
		return nil, errors.New("webhook URL must not contain user info")
	}

	if parsedURL.Host == "" {
		return nil, errors.New("webhook URL must include a host")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, errors.New("webhook URL must include a valid host")
	}

	if isLocalHostName(host) {
		return nil, errors.New("webhook URL host is not allowed")
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, errors.New("unable to resolve webhook host")
	}

	if len(ips) == 0 {
		return nil, errors.New("webhook host did not resolve to any IP address")
	}

	for _, ip := range ips {
		addr, ok := netip.AddrFromSlice(ip)
		if !ok {
