func testWebhookURL(parent context.Context, target *url.URL) error {
	timeoutCtx, cancel := context.WithTimeout(parent, 3*time.Second)
	defer cancel()

	transport := &http.Transport{
		Proxy: nil,
		DialContext: func(ctx context.Context, network, address string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(address)
			if err != nil {
				return nil, err
			}

			ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
				addr, ok := netip.AddrFromSlice(ip)
				if !ok {
					return nil, errors.New("invalid resolved IP address")
				}
				if isPrivateOrRestrictedIP(addr.Unmap()) {
					return nil, errors.New("connection to private or restricted IP is not allowed")
				}
			}

			var d net.Dialer
			return d.DialContext(ctx, network, net.JoinHostPort(host, port))
		},
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}

			if req.URL == nil {
				return errors.New("invalid redirect URL")
			}

			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return errors.New("redirected to unsupported scheme")
			}

			host := req.URL.Hostname()
			if host == "" || isLocalHostName(host) {
				return errors.New("redirected to disallowed host")
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return errors.New("unable to resolve redirect host")
			}
			for _, ip := range ips {
				addr, ok := netip.AddrFromSlice(ip)
				if !ok {
					return errors.New("invalid redirect IP address")
				}
				if isPrivateOrRestrictedIP(addr.Unmap()) {
					return errors.New("redirected to private or restricted IP")
				}
			}

			return nil
		},
	}

