	if err != nil {
		return err
	}
	req.Header.Set("Accept", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("webhook URL returned non-success status: %d", resp.StatusCode)
	}

	return nil
}

func saveWebhookURL(webhookURL string) {
	webhookStore.Lock()
	defer webhookStore.Unlock()
	webhookStore.URL = webhookURL
}

func isLocalHostName(host string) bool {
	h := strings.TrimSpace(strings.ToLower(host))
	return h == "localhost" || h == "localhost.localdomain"
}

func isPrivateOrRestrictedIP(ip netip.Addr) bool {
	return ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsMulticast() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsUnspecified()
}

