func validateWebhookURL(raw string) (*url.URL, error) {
	parsedURL, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("Invalid webhook URL format")
	}

	if !parsedURL.IsAbs() || parsedURL.Host == "" {
		return nil, errors.New("Invalid webhook URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("webhook URL must use http or https scheme")
	}

	if parsedURL.User != nil {
		return nil, errors.New("webhook URL must not contain user info")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, errors.New("webhook URL must include a valid host")
	}

	if isPrivateHost(host) {
		return nil, errors.New("webhook URL host is not allowed")
	}

	return parsedURL, nil
}

func testWebhookURL(target *url.URL) error {
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
	}

	transport := &http.Transport{
		Proxy: nil,
		DialContext: func(ctx context.Context, network, address string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(address)
			if err != nil {
				return nil, err
			}

			if isPrivateHost(host) {
				return nil, errors.New("webhook URL resolved to a disallowed address")
			}

			return dialer.DialContext(ctx, network, net.JoinHostPort(host, port))
		},
		ForceAttemptHTTP2:     false,
		ResponseHeaderTimeout: 3 * time.Second,
		TLSHandshakeTimeout:   3 * time.Second,
	}

	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
