		// Unique local addresses fc00::/7
		ula := netip.MustParsePrefix("fc00::/7")
		if ula.Contains(ip) {
			return true
		}
	}

	// Carrier-grade NAT 100.64.0.0/10
	if ip.Is4() {
		cgnat := netip.MustParsePrefix("100.64.0.0/10")
		if cgnat.Contains(ip) {
			return true
		}
	}

	return false
}

