)

type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type ConfigureWebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var (
	configMu          sync.RWMutex
	configuredWebhook string
)

func saveWebhook(url string) {
	configMu.Lock()
	defer configMu.Unlock()
	configuredWebhook = url
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "invalid webhook_url",
		})
	}

	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "failed to create test request",
		})
	}

	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook validation failed: received non-2xx status",
		})
	}

	saveWebhook(req.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		Success: true,
		Message: "webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	_ = app.Listen(":3000")
}

