// webhookRequest represents the expected JSON request body.
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// savedWebhookURL simulates persisted configuration storage.
var savedWebhookURL string

// ConfigureWebhook handles POST requests to configure a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid JSON format",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	parsedURL, err := validateWebhookURL(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	if err := testWebhookURL(ctx.Context(), parsedURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Save the configuration.
	savedWebhookURL = parsedURL.String()

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "webhook configured successfully",
		"webhook_url": savedWebhookURL,
	})
}

func validateWebhookURL(raw string) (*url.URL, error) {
	parsedURL, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("invalid webhook URL format")
	}

	if !parsedURL.IsAbs() {
		return nil, errors.New("webhook URL must be absolute")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("webhook URL must use http or https scheme")
	}

	if parsedURL.User != nil {
		return nil, errors.New("webhook URL must not contain user info")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, errors.New("webhook URL must include a host")
	}

	if isLocalOrPrivateHost(host) {
		return nil, errors.New("webhook URL host is not allowed")
	}

	return parsedURL, nil
}

func testWebhookURL(parentCtx context.Context, target *url.URL) error {
	dialer := &net.Dialer{
		Timeout: 2 * time.Second,
	}

	transport := &http.Transport{
		Proxy: nil,
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				host = addr
			}

			if isLocalOrPrivateHost(host) {
				return nil, errors.New("connection to local or private addresses is not allowed")
			}

			return dialer.DialContext(ctx, network, addr)
		},
		DisableKeepAlives:   true,
		TLSHandshakeTimeout: 2 * time.Second,
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}
			if isLocalOrPrivateHost(req.URL.Hostname()) {
				return errors.New("redirect to local or private addresses is not allowed")
			}
			return nil
		},
	}

	req, err := http.NewRequestWithContext(parentCtx, http.MethodGet, target.String(), nil)
	if err != nil {
		return errors.New("failed to create test request")
	}
	req.Header.Set("Accept", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		return errors.New("failed to send test request to webhook URL")
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return errors.New("webhook URL returned non-success status")
	}

	return nil
}

func isLocalOrPrivateHost(host string) bool {
	ip := net.ParseIP(host)
	if ip != nil {
		return isDisallowedIP(ip)
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return true
	}

	for _, resolvedIP := range ips {
		if isDisallowedIP(resolvedIP) {
			return true
		}
	}

	return false
}

func isDisallowedIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

	if ip.IsPrivate() {
		return true
	}

	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	if ip.Equal(net.ParseIP("0.0.0.0")) || ip.Equal(net.ParseIP("::")) {
		return true
	}

	return false
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	_ = json.Valid

	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

