package main

import (
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type WebhookConfigResponse struct {
	Success    bool   `json:"success"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

var (
	configMu          sync.RWMutex
	configuredWebhook string
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "invalid webhook_url",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	testReq, err := http.NewRequest(http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "failed to create test request",
		})
	}

	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "failed to reach webhook_url",
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url returned non-success status",
		})
	}

	configMu.Lock()
	configuredWebhook = req.WebhookURL
	configMu.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(WebhookConfigResponse{
		Success:    true,
		Message:    "webhook configured successfully",
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

